  const todayStrStr=new Date().toLocaleDateString('vi-VN');
  const currentShiftStats=useMemo(()=>{let cash=0,transfer=0,prof=0;history.filter(h=>new Date(Math.floor(h.id)).toLocaleDateString('vi-VN')===todayStrStr&&h.shift===shift).forEach(h=>{if(h.type==='BÁN'||h.type==='THU NỢ'||h.type==='TRẢ HÀNG'){if(h.paymentMethod==='CHUYỂN KHOẢN')transfer+=h.total;else if(h.paymentMethod==='TIỀN MẶT')cash+=h.total}if(h.type!=='NHẬP')prof+=(h.profit||0)});return{rev:cash+transfer,cash,transfer,prof}},[history,shift,todayStrStr]);
