  const groupedHistory=useMemo(()=>{let filtered=history;if(logTypeFilter!=="Tất cả")filtered=filtered.filter(log=>log.type===logTypeFilter);if(logSearchTerm.trim()!==""){const t=logSearchTerm.toLowerCase();filtered=filtered.filter(log=>(log.name&&log.name.toLowerCase().includes(t))||(log.customer&&log.customer.toLowerCase().includes(t)))}return filtered.reduce((groups:any,log:any)=>{const d=new Date(Math.floor(log.id)).toLocaleDateString('vi-VN');if(!groups[d])groups[d]=[];groups[d].push({...log,t:new Date(Math.floor(log.id)).toLocaleTimeString('vi-VN')});return groups},{})},[history,logSearchTerm,logTypeFilter]);

